using System;
using System.Collections.Generic;
using System.Xml;
using DefuseXml;

public class XmlConfigParser
{
    public static Dictionary<string, string> ParseXml(string xmlContent)
    {
        var settings = new Dictionary<string, string>();
        using (var reader = XmlReader.Create(new StringReader(xmlContent), new XmlReaderSettings { DtdProcessing = DtdProcessing.Prohibit }))
        {
            while (reader.Read())
            {
                if (reader.NodeType == XmlNodeType.Element && reader.HasAttributes)
                {
                    for (int i = 0; i < reader.AttributeCount; i++)
                    {
                        reader.MoveToAttribute(i);
                        settings[reader.Name] = reader.Value;
                    }
                }
            }
        }
        return settings;
    }
}